-- {"operators": "INNER_JOIN,AGGREGATE,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,ORDER_LINE", "delta": true}
WITH order_amt AS (SELECT OL_W_ID, OL_O_ID, OL_D_ID, SUM(OL_AMOUNT) AS amt FROM d_ORDER_LINE GROUP BY OL_W_ID, OL_O_ID, OL_D_ID) SELECT w.W_ID, d.D_ID, (oa.amt * (1 - c.C_DISCOUNT)) AS after_discount FROM d_WAREHOUSE w JOIN d_DISTRICT d ON w.W_ID = d.D_W_ID JOIN d_CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID JOIN order_amt oa ON c.C_W_ID = oa.OL_W_ID AND c.C_D_ID = oa.OL_D_ID;
